# solution.py
"""BookSynergy / Team Collaboration Manager.

A self-contained, thread-safe, in-memory backend service that powers a
collaborative reference-book / project platform.  It exposes the domain
operations a REST API would sit on top of:

* User management (registration, lookup, update, deletion)
* Project management (create, list, update, cascading delete)
* Task management (creation, assignment, status / deadline tracking)
* Messaging with threaded replies and file attachments
* A performance dashboard (completion rates, timings, peer ratings)
* Reporting (project progress, team & individual performance) with CSV and
  PDF export.

The implementation uses only the Python standard library.  A single shared
re-entrant lock guards every mutation so the manager is safe to use from many
threads at once, and every accessor returns deep copies so callers can never
mutate stored state by accident.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Sentinels
# ---------------------------------------------------------------------------
_UNSET = object()


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Authorization roles a user can hold."""

    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """The kind of report payload produced by the manager."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Domain entities
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment]
    created_at: datetime
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Internal store
# ---------------------------------------------------------------------------
class _Store:
    """A thin, lock-sharing container for a single entity type.

    All stores in a manager share one re-entrant lock so that any cross-entity
    operation is fully serialized.  The store itself only owns its ``items``
    mapping; the manager holds all indexes and business logic.
    """

    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock
        self.items: Dict[int, object] = {}


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Central façade coordinating every collaboration feature."""

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._now = now if now is not None else datetime.now
        self._lock = threading.RLock()

        # Entity stores -- all share the single lock above.
        self.users = _Store(self._lock)
        self.projects = _Store(self._lock)
        self.tasks = _Store(self._lock)
        self.messages = _Store(self._lock)
        self.performance = _Store(self._lock)  # holds Rating entities
        self.reports = _Store(self._lock)  # reserved for parity / future use

        # Global monotonically increasing id counter (ids unique across types).
        self._next_id = 1

        # Secondary indexes.
        self._username_index: Dict[str, int] = {}
        self._email_index: Dict[str, int] = {}
        self._tasks_by_project: Dict[int, set] = {}
        self._tasks_by_assignee: Dict[int, set] = {}
        self._messages_by_project: Dict[int, set] = {}
        self._messages_by_task: Dict[int, set] = {}
        self._ratings_by_ratee: Dict[int, set] = {}

    # ------------------------------------------------------------------
    # Helpers
    # ------------------------------------------------------------------
    def _allocate_id(self) -> int:
        with self._lock:
            new_id = self._next_id
            self._next_id += 1
            return new_id

    @staticmethod
    def _clone(obj):
        """Return a deep copy so callers cannot mutate stored state."""
        return copy.deepcopy(obj)

    @staticmethod
    def _is_blank(value) -> bool:
        return not isinstance(value, str) or value.strip() == ""

    @staticmethod
    def _valid_email(value) -> bool:
        return isinstance(value, str) and value.strip() != "" and "@" in value

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            if self._is_blank(username):
                raise ValidationError("username must be a non-empty string")
            if not self._valid_email(email):
                raise ValidationError("email must contain '@' and be non-empty")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            uname = username.strip()
            mail = email.strip()
            if uname in self._username_index:
                raise DuplicateError("username already registered")
            if mail in self._email_index:
                raise DuplicateError("email already registered")

            uid = self._allocate_id()
            user = User(uid, uname, mail, role, self._now())
            self.users.items[uid] = user
            self._username_index[uname] = uid
            self._email_index[mail] = uid
            return self._clone(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            user = self.users.items.get(user_id)
            if user is None:
                raise NotFoundError("user {0} not found".format(user_id))
            return self._clone(user)

    def list_users(self) -> List[User]:
        with self._lock:
            users = sorted(self.users.items.values(), key=lambda u: u.id)
            return [self._clone(u) for u in users]

    def update_user(self, user_id, username=_UNSET, email=_UNSET, role=_UNSET) -> User:
        with self._lock:
            user = self.users.items.get(user_id)
            if user is None:
                raise NotFoundError("user {0} not found".format(user_id))

            new_username = None
            new_email = None

            if username is not _UNSET:
                if self._is_blank(username):
                    raise ValidationError("username must be a non-empty string")
                new_username = username.strip()
                existing = self._username_index.get(new_username)
                if existing is not None and existing != user_id:
                    raise DuplicateError("username already registered")

            if email is not _UNSET:
                if not self._valid_email(email):
                    raise ValidationError("email must contain '@' and be non-empty")
                new_email = email.strip()
                existing = self._email_index.get(new_email)
                if existing is not None and existing != user_id:
                    raise DuplicateError("email already registered")

            if role is not _UNSET and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            # All validation passed -- apply mutations.
            if username is not _UNSET:
                self._username_index.pop(user.username, None)
                user.username = new_username
                self._username_index[new_username] = user_id

            if email is not _UNSET:
                self._email_index.pop(user.email, None)
                user.email = new_email
                self._email_index[new_email] = user_id

            if role is not _UNSET:
                user.role = role

            return self._clone(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            user = self.users.items.get(user_id)
            if user is None:
                raise NotFoundError("user {0} not found".format(user_id))

            for project in self.projects.items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns one or more projects")

            assigned = self._tasks_by_assignee.get(user_id, set())
            for tid in assigned:
                task = self.tasks.items.get(tid)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open (incomplete) tasks")

            # Detach the (necessarily completed) tasks from the user.
            for tid in list(assigned):
                task = self.tasks.items.get(tid)
                if task is not None:
                    task.assignee_id = None
            self._tasks_by_assignee.pop(user_id, None)

            self._username_index.pop(user.username, None)
            self._email_index.pop(user.email, None)
            del self.users.items[user_id]

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description="") -> Project:
        with self._lock:
            if self._is_blank(name):
                raise ValidationError("project name must be a non-empty string")
            if owner_id not in self.users.items:
                raise NotFoundError("owner {0} not found".format(owner_id))
            if end_date < start_date:
                raise ValidationError("end_date must not precede start_date")

            pid = self._allocate_id()
            project = Project(
                pid,
                name.strip(),
                description if description is not None else "",
                start_date,
                end_date,
                owner_id,
            )
            self.projects.items[pid] = project
            self._tasks_by_project.setdefault(pid, set())
            self._messages_by_project.setdefault(pid, set())
            return self._clone(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            project = self.projects.items.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))
            return self._clone(project)

    def list_projects(self) -> List[Project]:
        with self._lock:
            projects = sorted(self.projects.items.values(), key=lambda p: p.id)
            return [self._clone(p) for p in projects]

    def update_project(
        self,
        project_id,
        name=_UNSET,
        start_date=_UNSET,
        end_date=_UNSET,
        description=_UNSET,
    ) -> Project:
        with self._lock:
            project = self.projects.items.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))

            if name is not _UNSET and self._is_blank(name):
                raise ValidationError("project name must be a non-empty string")

            new_start = project.start_date if start_date is _UNSET else start_date
            new_end = project.end_date if end_date is _UNSET else end_date
            if new_end < new_start:
                raise ValidationError("end_date must not precede start_date")

            if name is not _UNSET:
                project.name = name.strip()
            if start_date is not _UNSET:
                project.start_date = start_date
            if end_date is not _UNSET:
                project.end_date = end_date
            if description is not _UNSET:
                project.description = description if description is not None else ""

            return self._clone(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            project = self.projects.items.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))

            for tid in list(self._tasks_by_project.get(project_id, set())):
                self._remove_task(tid)
            self._tasks_by_project.pop(project_id, None)

            for mid in list(self._messages_by_project.get(project_id, set())):
                self._remove_message(mid)
            self._messages_by_project.pop(project_id, None)

            del self.projects.items[project_id]

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None) -> Task:
        with self._lock:
            project = self.projects.items.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))
            if self._is_blank(title):
                raise ValidationError("task title must be a non-empty string")
            if assignee_id is not None and assignee_id not in self.users.items:
                raise NotFoundError("assignee {0} not found".format(assignee_id))
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not precede project start")

            tid = self._allocate_id()
            task = Task(
                tid,
                project_id,
                title.strip(),
                TaskStatus.NOT_STARTED,
                assignee_id,
                deadline,
                None,
                None,
                self._now(),
            )
            self.tasks.items[tid] = task
            self._tasks_by_project.setdefault(project_id, set()).add(tid)
            if assignee_id is not None:
                self._tasks_by_assignee.setdefault(assignee_id, set()).add(tid)
            return self._clone(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            task = self.tasks.items.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            return self._clone(task)

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            if project_id not in self.projects.items:
                raise NotFoundError("project {0} not found".format(project_id))
            return self._collect_tasks(self._tasks_by_project.get(project_id, set()))

    def list_tasks_by_assignee(self, assignee_id) -> List[Task]:
        with self._lock:
            if assignee_id not in self.users.items:
                raise NotFoundError("user {0} not found".format(assignee_id))
            return self._collect_tasks(self._tasks_by_assignee.get(assignee_id, set()))

    def assign_task(self, task_id, assignee_id) -> Task:
        return self._set_assignee(task_id, assignee_id, require_assignee=True)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        return self._set_assignee(task_id, new_assignee_id, require_assignee=True)

    def unassign_task(self, task_id) -> Task:
        return self._set_assignee(task_id, None, require_assignee=False)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self.tasks.items.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            if deadline is not None:
                project = self.projects.items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline must not precede project start")
            task.deadline = deadline
            return self._clone(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            task = self.tasks.items.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now

            task.status = status
            return self._clone(task)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ) -> Message:
        with self._lock:
            if author_id not in self.users.items:
                raise NotFoundError("author {0} not found".format(author_id))

            if project_id is not None and task_id is not None:
                raise ValidationError("message must target either a project or a task, not both")
            if project_id is None and task_id is None:
                raise ValidationError("message must target a project or a task")

            if project_id is not None and project_id not in self.projects.items:
                raise NotFoundError("project {0} not found".format(project_id))
            if task_id is not None and task_id not in self.tasks.items:
                raise NotFoundError("task {0} not found".format(task_id))

            attachment_specs = list(attachments) if attachments else []
            has_body = isinstance(body, str) and body.strip() != ""
            if not has_body and not attachment_specs:
                raise ValidationError("message must have a body or at least one attachment")

            if parent_id is not None and parent_id not in self.messages.items:
                raise NotFoundError("parent message {0} not found".format(parent_id))

            now = self._now()
            attachment_objs = [
                Attachment(filename, len(data), author_id, now)
                for (filename, data) in attachment_specs
            ]

            mid = self._allocate_id()
            message = Message(
                mid,
                author_id,
                body if isinstance(body, str) else "",
                project_id,
                task_id,
                parent_id,
                attachment_objs,
                now,
                None,
            )
            self.messages.items[mid] = message
            if project_id is not None:
                self._messages_by_project.setdefault(project_id, set()).add(mid)
            if task_id is not None:
                self._messages_by_task.setdefault(task_id, set()).add(mid)
            return self._clone(message)

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self.messages.items.get(message_id)
            if message is None:
                raise NotFoundError("message {0} not found".format(message_id))
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit this message")
            if self._is_blank(new_body):
                raise ValidationError("message body must be a non-empty string")
            message.body = new_body
            message.edited_at = self._now()
            return self._clone(message)

    def add_attachment(self, message_id, user_id, filename, data) -> Message:
        with self._lock:
            message = self.messages.items.get(message_id)
            if message is None:
                raise NotFoundError("message {0} not found".format(message_id))
            if message.author_id != user_id:
                raise AuthorizationError("only the author may attach to this message")
            if self._is_blank(filename):
                raise ValidationError("filename must be a non-empty string")
            message.attachments.append(
                Attachment(filename, len(data), user_id, self._now())
            )
            return self._clone(message)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            if project_id not in self.projects.items:
                raise NotFoundError("project {0} not found".format(project_id))
            return self._collect_messages(self._messages_by_project.get(project_id, set()))

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            if task_id not in self.tasks.items:
                raise NotFoundError("task {0} not found".format(task_id))
            return self._collect_messages(self._messages_by_task.get(task_id, set()))

    def delete_message(self, message_id, user_id) -> None:
        with self._lock:
            message = self.messages.items.get(message_id)
            if message is None:
                raise NotFoundError("message {0} not found".format(message_id))
            if message.author_id != user_id:
                raise AuthorizationError("only the author may delete this message")
            self._remove_message(message_id)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            durations = self._completion_durations(tasks)
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        with self._lock:
            if rater_id not in self.users.items:
                raise NotFoundError("rater {0} not found".format(rater_id))
            if ratee_id not in self.users.items:
                raise NotFoundError("ratee {0} not found".format(ratee_id))
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool) or score < 1 or score > 5:
                raise ValidationError("score must be an integer between 1 and 5")
            if task_id is not None and task_id not in self.tasks.items:
                raise NotFoundError("task {0} not found".format(task_id))

            rid = self._allocate_id()
            rating = Rating(
                rid,
                rater_id,
                ratee_id,
                score,
                feedback if feedback is not None else "",
                task_id,
                self._now(),
            )
            self.performance.items[rid] = rating
            self._ratings_by_ratee.setdefault(ratee_id, set()).add(rid)
            return self._clone(rating)

    def get_ratings_summary(self, user_id) -> Dict[str, object]:
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_for_ratee(user_id)
            if not ratings:
                return {"count": 0, "average": 0.0, "ratings": []}
            average = sum(r.score for r in ratings) / len(ratings)
            return {
                "count": len(ratings),
                "average": average,
                "ratings": [self._clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> Dict[str, object]:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            completion_rate = (completed / total) if total else 0.0

            durations = self._completion_durations(tasks)
            avg_time = (sum(durations) / len(durations)) if durations else None

            ratings = self._ratings_for_ratee(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def project_progress_report(self, project_id) -> Dict[str, object]:
        with self._lock:
            if project_id not in self.projects.items:
                raise NotFoundError("project {0} not found".format(project_id))

            tasks = self._tasks_for_project(project_id)
            total = len(tasks)
            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = (completed / total) if total else 0.0

            now = self._now()
            overdue = sum(
                1
                for t in tasks
                if t.deadline is not None
                and t.status != TaskStatus.COMPLETED
                and t.deadline < now
            )

            per_assignee: Dict[int, Dict[str, object]] = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                stats = per_assignee.setdefault(
                    task.assignee_id, {"total": 0, "completed": 0}
                )
                stats["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    stats["completed"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None) -> Dict[str, object]:
        with self._lock:
            if project_id is not None and project_id not in self.projects.items:
                raise NotFoundError("project {0} not found".format(project_id))

            if project_id is not None:
                tasks = self._tasks_for_project(project_id)
            else:
                tasks = list(self.tasks.items.values())

            user_ids = sorted(
                {t.assignee_id for t in tasks if t.assignee_id is not None}
            )
            rows = []
            for uid in user_ids:
                user_tasks = [t for t in tasks if t.assignee_id == uid]
                total = len(user_tasks)
                completed = sum(
                    1 for t in user_tasks if t.status == TaskStatus.COMPLETED
                )
                durations = self._completion_durations(user_tasks)
                avg_time = (sum(durations) / len(durations)) if durations else None
                rows.append(
                    {
                        "user_id": uid,
                        "total_tasks": total,
                        "completed_tasks": completed,
                        "completion_rate": (completed / total) if total else 0.0,
                        "average_completion_time": avg_time,
                    }
                )

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> Dict[str, object]:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            completion_rate = (completed / total) if total else 0.0
            durations = self._completion_durations(tasks)
            avg_time = (sum(durations) / len(durations)) if durations else None

            ratings = self._ratings_for_ratee(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )

            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": [self._clone(t) for t in tasks],
            }

    def export_report(self, report, report_format):
        if not isinstance(report, dict):
            raise ValidationError("report must be a dictionary produced by a report method")
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")

        if report_format == ReportFormat.CSV:
            return self._report_to_csv(report)
        return self._report_to_pdf(report)

    # ------------------------------------------------------------------
    # Internal: assignment helper
    # ------------------------------------------------------------------
    def _set_assignee(self, task_id, assignee_id, require_assignee) -> Task:
        with self._lock:
            task = self.tasks.items.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            if require_assignee and assignee_id not in self.users.items:
                raise NotFoundError("assignee {0} not found".format(assignee_id))

            old = task.assignee_id
            if old is not None and old in self._tasks_by_assignee:
                self._tasks_by_assignee[old].discard(task_id)

            task.assignee_id = assignee_id
            if assignee_id is not None:
                self._tasks_by_assignee.setdefault(assignee_id, set()).add(task_id)
            return self._clone(task)

    # ------------------------------------------------------------------
    # Internal: removal helpers
    # ------------------------------------------------------------------
    def _remove_task(self, task_id) -> None:
        task = self.tasks.items.pop(task_id, None)
        if task is None:
            return
        if task.project_id in self._tasks_by_project:
            self._tasks_by_project[task.project_id].discard(task_id)
        if task.assignee_id is not None and task.assignee_id in self._tasks_by_assignee:
            self._tasks_by_assignee[task.assignee_id].discard(task_id)
        for mid in list(self._messages_by_task.get(task_id, set())):
            self._remove_message(mid)
        self._messages_by_task.pop(task_id, None)

    def _remove_message(self, message_id) -> None:
        message = self.messages.items.pop(message_id, None)
        if message is None:
            return
        if message.project_id is not None and message.project_id in self._messages_by_project:
            self._messages_by_project[message.project_id].discard(message_id)
        if message.task_id is not None and message.task_id in self._messages_by_task:
            self._messages_by_task[message.task_id].discard(message_id)

    # ------------------------------------------------------------------
    # Internal: collection helpers
    # ------------------------------------------------------------------
    def _collect_tasks(self, ids) -> List[Task]:
        tasks = [self.tasks.items[i] for i in ids if i in self.tasks.items]
        tasks.sort(key=lambda t: t.id)
        return [self._clone(t) for t in tasks]

    def _collect_messages(self, ids) -> List[Message]:
        messages = [self.messages.items[i] for i in ids if i in self.messages.items]
        messages.sort(key=lambda m: m.id)
        return [self._clone(m) for m in messages]

    def _tasks_for_project(self, project_id) -> List[Task]:
        ids = self._tasks_by_project.get(project_id, set())
        tasks = [self.tasks.items[i] for i in ids if i in self.tasks.items]
        tasks.sort(key=lambda t: t.id)
        return tasks

    def _tasks_for_assignee(self, user_id) -> List[Task]:
        ids = self._tasks_by_assignee.get(user_id, set())
        tasks = [self.tasks.items[i] for i in ids if i in self.tasks.items]
        tasks.sort(key=lambda t: t.id)
        return tasks

    def _ratings_for_ratee(self, user_id) -> List[Rating]:
        ids = self._ratings_by_ratee.get(user_id, set())
        ratings = [self.performance.items[i] for i in ids if i in self.performance.items]
        ratings.sort(key=lambda r: r.id)
        return ratings

    @staticmethod
    def _completion_durations(tasks) -> List[float]:
        durations = []
        for task in tasks:
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append((task.completed_at - task.started_at).total_seconds())
        return durations

    def _require_user(self, user_id) -> None:
        if user_id not in self.users.items:
            raise NotFoundError("user {0} not found".format(user_id))

    # ------------------------------------------------------------------
    # Internal: export helpers
    # ------------------------------------------------------------------
    @staticmethod
    def _stringify(value) -> str:
        if isinstance(value, Enum):
            return str(value.value)
        return str(value)

    def _report_to_csv(self, report) -> str:
        output = io.StringIO()
        writer = csv.writer(output)
        rows = report.get("rows")

        if isinstance(rows, list) and rows and all(isinstance(r, dict) for r in rows):
            fieldnames: List[str] = []
            for row in rows:
                for key in row.keys():
                    if key not in fieldnames:
                        fieldnames.append(key)
            writer.writerow(fieldnames)
            for row in rows:
                writer.writerow([self._stringify(row.get(name, "")) for name in fieldnames])
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([self._stringify(key), self._stringify(value)])

        return output.getvalue()

    def _report_to_pdf(self, report) -> bytes:
        lines = ["BookSynergy Report"]
        rtype = report.get("report_type")
        if rtype is not None:
            lines.append("Type: {0}".format(self._stringify(rtype)))
        for key, value in report.items():
            if key == "report_type":
                continue
            lines.append("{0}: {1}".format(self._stringify(key), self._stringify(value)))
        return self._build_pdf(lines)

    @staticmethod
    def _build_pdf(lines) -> bytes:
        def escape(text: str) -> str:
            return (
                text.replace("\\", "\\\\")
                .replace("(", "\\(")
                .replace(")", "\\)")
            )

        content_parts = ["BT", "/F1 12 Tf", "72 720 Td", "14 TL"]
        for index, line in enumerate(lines):
            safe = escape(str(line))
            if index > 0:
                content_parts.append("T*")
            content_parts.append("({0}) Tj".format(safe))
        content_parts.append("ET")
        content = "\n".join(content_parts)
        content_bytes = content.encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            (
                b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
                b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>"
            ),
            (
                b"<< /Length "
                + str(len(content_bytes)).encode("ascii")
                + b" >>\nstream\n"
                + content_bytes
                + b"\nendstream"
            ),
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        pdf = bytearray()
        pdf += b"%PDF-1.4\n"
        offsets = []
        for number, body in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += str(number).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

        xref_position = len(pdf)
        size = len(objects) + 1
        pdf += b"xref\n"
        pdf += b"0 " + str(size).encode("ascii") + b"\n"
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += ("%010d 00000 n \n" % offset).encode("ascii")
        pdf += b"trailer\n<< /Size " + str(size).encode("ascii") + b" /Root 1 0 R >>\n"
        pdf += b"startxref\n" + str(xref_position).encode("ascii") + b"\n%%EOF\n"
        return bytes(pdf)
